    const data = {
      lastUpdate: Date.now(),
      currentDepth: this.currentDepth,
      insights: Object.fromEntries(this.insights)
    };
    fs.writeFileSync(this.spiralPath, JSON.stringify(data, null, 2), 'utf-8');
  }

